import re
bytes_=[]
for line in open('/tmp/vram.txt'):
    m=re.match(r'0*([0-9a-fA-F]+):(.*)',line.strip())
    if not m: continue
    for tok in re.findall(r"'(.)'|'(\\x[0-9a-f]{2})'", m.group(2)):
        v=tok[0] or tok[1]
        if v.startswith('\\x'): bytes_.append(int(v[2:],16))
        else: bytes_.append(ord(v))
# chars at even indices
chars=[chr(bytes_[i]) if 32<=bytes_[i]<127 else ' ' for i in range(0,len(bytes_),2)]
for r in range(25):
    row=''.join(chars[r*80:(r+1)*80]).rstrip()
    if row.strip(): print('%2d|%s'%(r,row))
